 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	import NodeNetworkConfigurationPolicyModel from 'src/console-models/NodeNetworkConfigurationPolicyModel';
 4	import { useNMStateTranslation } from 'src/utils/hooks/useNMStateTranslation';
 5	
 6	import { useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 7	import { Alert, AlertVariant, Breadcrumb, BreadcrumbItem } from '@patternfly/react-core';
 8	import { V1NodeNetworkConfigurationPolicy } from '@types';
 9	import { getResourceUrl } from '@utils/helpers';
10	
11	import PolicyActions from '../actions/PolicyActions';
12	import { isPolicySupported } from '../utils';
13	
14	import './policy-page-title.scss';
15	
16	type PolicyPageTitleProps = {
17	  policy: V1NodeNetworkConfigurationPolicy;
18	  name: string;
19	};
20	
21	const PolicyPageTitle: FC<PolicyPageTitleProps> = ({ policy, name }) => {
22	  const { t } = useNMStateTranslation();
23	  const formSupported = isPolicySupported(policy);
24	
25	  const [canUpdatePolicy] = useAccessReview({
26	    verb: 'update',
27	    resource: NodeNetworkConfigurationPolicyModel.plural,
28	  });
29	
30	  return (
31	    <>
32	      <div className="pf-v6-c-page__main-breadcrumb">
33	        <Breadcrumb className="pf-v6-c-breadcrumb co-breadcrumb">
34	          <BreadcrumbItem>
35	            <Link to={getResourceUrl({ model: NodeNetworkConfigurationPolicyModel })}>
36	              {t(NodeNetworkConfigurationPolicyModel.label)}
37	            </Link>
38	          </BreadcrumbItem>
39	          <BreadcrumbItem>
40	            {t('{{modelName}} details', { modelName: NodeNetworkConfigurationPolicyModel.label })}
41	          </BreadcrumbItem>
42	        </Breadcrumb>
43	      </div>
44	      <div className="co-m-nav-title co-m-nav-title--detail co-m-nav-title--breadcrumbs">
45	        <span className="co-m-pane__heading">
46	          <h1 className="co-m-pane__name co-resource-item">
47	            <span className="co-m-resource-icon co-m-resource-icon--lg">
48	              {NodeNetworkConfigurationPolicyModel.abbr}
49	            </span>
50	            <span data-test-id="resource-title" className="co-resource-item__resource-name">
51	              {name ?? policy?.metadata?.name}{' '}
52	            </span>
53	          </h1>
54	          <div className="co-actions">
55	            <PolicyActions policy={policy} />
56	          </div>
57	        </span>
58	
59	        {policy && canUpdatePolicy === false && (
60	          <Alert
61	            className="pf-u-mb-md"
62	            isInline
63	            variant={AlertVariant.info}
64	            title={t("You're in view-only mode")}
65	          >
66	            {t('To edit this policy, contact your administrator.')}
67	          </Alert>
68	        )}
69	        {policy && canUpdatePolicy && !formSupported && (
70	          <Alert
71	            variant={AlertVariant.info}
72	            isInline
73	            title={t('This policy must be edited via YAML')}
74	            className="pf-u-mb-md"
75	          />
76	        )}
77	      </div>
78	    </>
79	  );
80	};
81	
82	export default PolicyPageTitle;

